/**
 Test if the input body HTML has only tags and attributes allowed by the Whitelist. Useful for form validation.
 <p>The input HTML should still be run through the cleaner to set up enforced attributes, and to tidy the output.
 <p>Assumes the HTML is a body fragment (i.e. will be used in an existing HTML document body.)
 @param bodyHtml HTML to test
 @param whitelist whitelist to test against
 @return true if no tags or attributes were removed; false otherwise
 @see #clean(String, org.jsoup.safety.Whitelist)
 */
public static boolean isValid(String bodyHtml, Whitelist whitelist) {
    // Check for parsing errors by parsing with error tracking enabled
    ParseErrorList errors = ParseErrorList.tracking(1); // Only need to know if there are any errors
    Document doc = Parser.parseBodyFragment(bodyHtml, "", errors);

    // If there are parse errors, the HTML is not valid
    if (!errors.isEmpty()) {
        return false;
    }

    // If no parse errors, check if tags and attributes are safe according to whitelist
    return new Cleaner(whitelist).isValid(doc);
